import{_ as o,o as a,c as e,a2 as r}from"./chunks/framework.e-meDy3u.js";const q=JSON.parse('{"title":"总览与背景","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),d={name:"overview.md"};function s(n,t,p,h,i,u){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="总览与背景" tabindex="-1">总览与背景 <a class="header-anchor" href="#总览与背景" aria-label="Permalink to &quot;总览与背景&quot;">​</a></h1><p class="hqq-lede">这不是一份方案书。这是七道真实的问题，和经过反复推敲之后我觉得最站得住脚的答案。</p><h2 id="关键背景" tabindex="-1">关键背景 <a class="header-anchor" href="#关键背景" aria-label="Permalink to &quot;关键背景&quot;">​</a></h2><p>几件事必须先讲清楚，因为它们决定了后面每道题答的方向。</p><p><strong>昊七七是一家正在赢的公司，不是还没跑通的公司。</strong> 抖音速食面热销榜第二，业绩已经验证。给正在赢的公司讲方案，逻辑要反过来——不能暗示它们现在靠运气，不能一上来就说&quot;你们这样不对&quot;。我来这里是加固地基、放大已有优势，不是重排你们怎么运转。</p><p><strong>老板和直属上级都是大厂经理出身。</strong> 他们听到&quot;降本增效、标准化、可复制、护城河&quot;这类词，母语级认同。听到&quot;全自动 AI 系统&quot;、&quot;帮你们做爆款&quot;，本能警惕——因为他们见过太多演示好看、上线即死的东西。</p><p><strong>GMV 两条腿：自有私店 + 代理店。</strong> 这决定了方案的骨架：库同时是两条腿的军火库，但起手先在自有私店跑通做样板，样板有了再放大给代理。</p><p><strong>公司规模：部门齐全，每个部门可能就一两个人。</strong> 人人身兼数职，不可能给 AI 项目专门配运营。方案必须&quot;轻&quot;，轻到让现有的人顺手就能用上。</p><hr><h2 id="贯穿全案的主线" tabindex="-1">贯穿全案的主线 <a class="header-anchor" href="#贯穿全案的主线" aria-label="Permalink to &quot;贯穿全案的主线&quot;">​</a></h2><p>一条线，三步：</p><p><strong>库 → 自有私店样板 → 代理店放大</strong></p><p>地基是一个爆款素材资产库。两个进料口：已有的爆款归库（把赢过的沉淀下来），技术面那个原型工作流持续生成新候选。</p><p>第一步先在自有私店把这个库跑通。哪条素材该放量、该二创，库直接喂私店的投放决策。这一步入职就能碰，不依赖任何外部的人。</p><p>第二步：自动回写 + 自排名，决策提速；真正的推理 Agent 介入（聚类客服原话、出复盘假设）。</p><p>第三步：把跑通的样板放大给代理店。这才是那个大乘法。样板没跑通，放大器放大的是空气。</p><hr><h2 id="待确认的承重假设" tabindex="-1">待确认的承重假设 <a class="header-anchor" href="#待确认的承重假设" aria-label="Permalink to &quot;待确认的承重假设&quot;">​</a></h2><p>七道题的答案里，有三个假设还没核实。面试现场可以直接反问老板。</p><table tabindex="0"><thead><tr><th>编号</th><th>待确认</th><th>影响范围</th><th>备选 Plan B</th></tr></thead><tbody><tr><td>Q-C</td><td>自有私店有多少可投放体量？我第一周能不能真的碰到、拿到数据？</td><td><strong>最重要。整条&quot;先私店样板再放大&quot;的主线都压在上面。</strong></td><td>若私店体量很小，换 1-2 个最配合的代理跑样板，逻辑不变，起跑点换。</td></tr><tr><td>Q-A</td><td>代理店是挂昊七七链接分销，还是各自开店自己卖？</td><td>只影响第三步放大层怎么铺（主动 push 还是做成货架）。不影响地基和第一步。</td><td>两手准备详见附录。</td></tr><tr><td>Q-B</td><td>公司&quot;赢&quot;建立在几个人的手感上，还是已有固定打法？</td><td>Q1、Q7 的表达角度。若靠手感，&quot;把高手判断沉淀成规则&quot;最站得住。</td><td>话术调整，框架不变。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">为什么 Q-C 比 Q-A 更重要</p><p>Q-A 曾经是全案最大的假设（早期版本把代理分发当第一步）。现在主线改成&quot;先服务自有私店&quot;之后，Q-A 降级为延伸层的实现细节。Q-C 才是承重假设——你没法把一个自己都还没跑通的流程当样板展示。入职第一周就得核。</p></div><hr><h2 id="贯穿全场的姿态" tabindex="-1">贯穿全场的姿态 <a class="header-anchor" href="#贯穿全场的姿态" aria-label="Permalink to &quot;贯穿全场的姿态&quot;">​</a></h2><p>七道题里，凡涉及定规范、改流程、设硬约束的地方，都摆成&quot;给老板的建议 / 需要老板拍板&quot;，不是&quot;我一个新人要推行的事&quot;。</p><p>一句话定调：<strong>你们这套打法已经被市场验证了，我不动它，我只想把散在个人和群里的赢法沉淀下来、让它更省人、更能被更多人复用。</strong></p>',25)])])}const c=o(d,[["render",s]]);export{q as __pageData,c as default};
